import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { api } from '../services/api';
import './LeaderboardPage.css';

function LeaderboardPage() {
  const navigate = useNavigate();
  const [leaders, setLeaders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadLeaderboard();
  }, []);

  const loadLeaderboard = async () => {
    try {
      const data = await api.getLeaderboard();
      setLeaders(data);
    } catch (error) {
      console.error('Failed to load leaderboard:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="leaderboard-page">
      <nav className="navbar">
        <div className="nav-brand">🚀 Abzorithm</div>
        <div className="nav-menu">
          <button className="nav-link" onClick={() => navigate('/problems')}>
            Problems
          </button>
          <button className="nav-link active">Leaderboard</button>
        </div>
      </nav>

      <div className="content">
        <div className="page-header">
          <h1>🏆 Leaderboard</h1>
          <p>Top performers this month</p>
        </div>

        <div className="leaderboard-list">
          {leaders.map((user, index) => {
            const rank = index + 1;
            const medal = rank === 1 ? '🥇' : rank === 2 ? '🥈' : rank === 3 ? '🥉' : '';

            return (
              <div key={user.id} className="leader-item">
                <div className="rank">{medal || rank}</div>
                <div className="avatar">
                  {user.username?.charAt(0).toUpperCase()}
                </div>
                <div className="info">
                  <div className="name">{user.username}</div>
                  <div className="country">{user.country || 'Unknown'}</div>
                </div>
                <div className="score">{user.score || 0}</div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

export default LeaderboardPage;
